import React, { useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import resume from "../../data/resume";
import "./Home.css";

function FloatingOrb({ style }) {
  return <div className="orb" style={style} />;
}

export default function Home() {
  const heroRef = useRef(null);

  useEffect(() => {
    const el = heroRef.current;
    if (!el) return;

    const onMove = (e) => {
      const { clientX: x, clientY: y } = e;
      const cx = window.innerWidth / 2;
      const cy = window.innerHeight / 2;

      const rotX = ((y - cy) / cy) * -8;
      const rotY = ((x - cx) / cx) * 8;

      el.style.transform = `perspective(1200px) rotateX(${rotX}deg) rotateY(${rotY}deg)`;
    };

    const onLeave = () => {
      el.style.transform = "perspective(1200px) rotateX(0) rotateY(0)";
    };

    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseleave", onLeave);

    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseleave", onLeave);
    };
  }, []);

  return (
    <div className="home page-enter">

      {/* Background Orbs */}
      <FloatingOrb
        style={{
          width: 500,
          height: 500,
          top: "-10%",
          left: "-5%",
          background:
            "radial-gradient(circle, rgba(230,57,70,0.12) 0%, transparent 70%)",
        }}
      />

      <FloatingOrb
        style={{
          width: 400,
          height: 400,
          bottom: "10%",
          right: "-5%",
          background:
            "radial-gradient(circle, rgba(76,201,240,0.1) 0%, transparent 70%)",
        }}
      />

      <div className="hero-grid">

        {/* Left Side */}
        <div className="hero-text" ref={heroRef}>

          <p className="hero-tag">
            <span className="tag-dot" />
            Available for opportunities
          </p>

          <h1 className="hero-name">
            <span className="name-first">{resume.firstName}</span>
            <span className="name-last">
              {resume.lastName}
            </span>
          </h1>

          <p className="hero-role">
            {resume.role}
            <span className="role-divider"> / </span>
            CS Undergraduate
            <br />
            <span className="hero-sub">
              {resume.company} · {resume.college} · GPA {resume.gpa}
            </span>
          </p>

          <div className="hero-actions">
            <Link to="/projects" className="btn-primary">
              View Projects →
            </Link>
            <Link to="/contact" className="btn-outline">
              Get In Touch
            </Link>
          </div>

          <div className="hero-stats">
            <div className="stat">
              <span className="stat-num">{resume.gpa}</span>
              <span className="stat-label">GPA</span>
            </div>

            <div className="stat-divider" />

            <div className="stat">
              <span className="stat-num">{resume.projects}</span>
              <span className="stat-label">Projects</span>
            </div>

            <div className="stat-divider" />

            <div className="stat">
              <span className="stat-num">{resume.certificates}</span>
              <span className="stat-label">Certs</span>
            </div>
          </div>
        </div>

        {/* Right Side Card */}
        <div className="hero-card-wrap">
          <div className="hero-card">

            <div className="card-header">
              <div>
                <p className="card-name">{resume.name}</p>
                <p className="card-title">{resume.role}</p>
              </div>
            </div>

            <div className="card-divider" />

            <div className="card-stack">
              {resume.skills.map((skill) => (
                <span key={skill} className="card-tag">
                  {skill}
                </span>
              ))}
            </div>

            <div className="card-project">
              <p className="cp-label">Latest Project</p>
              <a
                href={resume.projectLink}
                target="_blank"
                rel="noreferrer"
                className="cp-link"
              >
                {resume.projectName} ↗
              </a>
            </div>

            <div className="card-footer">
              <a
                href={resume.github}
                target="_blank"
                rel="noreferrer"
                className="cf-item"
              >
                ⌨ GitHub
              </a>

              <a href={`mailto:${resume.email}`} className="cf-item">
                ✉ Email
              </a>
            </div>

          </div>
        </div>
      </div>

      <div className="scroll-hint">
        <span>Scroll</span>
        <div className="scroll-line" />
      </div>
    </div>
  );
}
